import React, { useState, useEffect } from 'react';

interface DaySelectionModalProps {
    onClose: () => void;
    onGenerate: (selectedDays: string[]) => void;
}

const dayNamesHebrew: Record<string, string> = {
    sunday: 'ראשון',
    monday: 'שני',
    tuesday: 'שלישי',
    wednesday: 'רביעי',
    thursday: 'חמישי',
};

// Map JS getDay() (0=Sun) to our string keys
const jsDayToKey: Record<number, string> = {
    0: 'sunday',
    1: 'monday',
    2: 'tuesday',
    3: 'wednesday',
    4: 'thursday'
};

const DaySelectionModal: React.FC<DaySelectionModalProps> = ({ onClose, onGenerate }) => {
    const [availableDays, setAvailableDays] = useState<string[]>([]);
    const [selectedDays, setSelectedDays] = useState<Set<string>>(new Set());
    const [isLate, setIsLate] = useState(false);

    useEffect(() => {
        // 1. Time-Aware Logic: Determine what days are left in the week
        const today = new Date();
        const currentDayNum = today.getDay(); // 0 is Sunday, 4 is Thursday
        const currentHour = today.getHours();

        // If it's Friday (5) or Saturday (6), we just offer the whole next week (Sun-Thu)
        let startDayIndex = currentDayNum;
        if (currentDayNum > 4) {
            startDayIndex = 0;
        }

        const daysLeft: string[] = [];
        for (let i = startDayIndex; i <= 4; i++) {
            daysLeft.push(jsDayToKey[i]);
        }

        setAvailableDays(daysLeft);

        // Select all available days by default
        setSelectedDays(new Set(daysLeft));

        // Check if it's late in the day (e.g., after 16:00) so we can warn them about "Today"
        if (currentHour >= 16 && currentDayNum <= 4) {
            setIsLate(true);
        }
    }, []);

    const toggleDay = (day: string) => {
        const newSelection = new Set(selectedDays);
        if (newSelection.has(day)) {
            newSelection.delete(day);
        } else {
            newSelection.add(day);
        }
        setSelectedDays(newSelection);
    };

    const handleGenerate = () => {
        if (selectedDays.size === 0) return;
        onGenerate(Array.from(selectedDays));
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-bg/80 backdrop-blur-sm p-4 fade-in">
            <div className="w-full max-w-md bg-surface border border-surface-hover rounded-2xl shadow-2xl p-6 relative overflow-hidden">

                {/* Decorative element */}
                <div className="absolute top-0 right-0 w-32 h-32 bg-primary opacity-10 blur-2xl rounded-full translate-x-12 -translate-y-12"></div>

                <h2 className="title-gradient text-2xl mb-2 relative z-10">תכנון ארוחות קדימה</h2>
                <p className="text-muted text-sm mb-6 relative z-10">
                    בחר לאילו ימים תרצה עד יום חמישי.
                </p>

                {isLate && availableDays.length > 0 && availableDays[0] === jsDayToKey[new Date().getDay()] && (
                    <div className="mb-4 p-3 bg-blue-500/10 border border-blue-500/20 rounded-lg text-xs text-blue-200">
                        <span className="font-bold">שים לב:</span> השעה כבר מאוחרת. אם תבחר להפיק תפריט ל"היום", ה-AI יספק לך רק הצעות לארוחת ערב ונשנוש לילה.
                    </div>
                )}

                <div className="space-y-3 mb-8">
                    {availableDays.map((day) => {
                        const isSelected = selectedDays.has(day);
                        return (
                            <label
                                key={day}
                                className={`flex items-center p-4 rounded-xl cursor-pointer border transition-all ${isSelected ? 'bg-primary/10 border-primary' : 'bg-bg border-surface-hover hover:border-text-muted'
                                    }`}
                                onClick={() => toggleDay(day)}
                            >
                                <div className={`w-6 h-6 rounded-md flex items-center justify-center ml-3 transition-colors ${isSelected ? 'bg-primary text-white' : 'border-2 border-surface-hover'
                                    }`}>
                                    {isSelected && <span className="text-sm">✓</span>}
                                </div>
                                <span className={`font-medium ${isSelected ? 'text-white' : 'text-muted'}`}>
                                    יום {dayNamesHebrew[day]}
                                </span>

                                {/* Indicate if it's "Today" */}
                                {day === jsDayToKey[new Date().getDay()] && new Date().getDay() <= 4 && (
                                    <span className="mr-auto text-xs bg-surface px-2 py-1 rounded text-muted">היום</span>
                                )}
                            </label>
                        );
                    })}

                    {availableDays.length === 0 && (
                        <div className="text-center p-6 text-muted border border-surface-hover border-dashed rounded-xl">
                            סוף השבוע הגיע! אין ימים לתכנן כרגע. אפשר להתחיל לתכנן את שבוע הבא במוצאי שבת.
                        </div>
                    )}
                </div>

                <div className="flex gap-3">
                    <button
                        className="btn-secondary flex-1"
                        onClick={onClose}
                    >
                        ביטול
                    </button>
                    <button
                        className="btn-primary flex-1 disabled:opacity-50 disabled:cursor-not-allowed"
                        disabled={selectedDays.size === 0}
                        onClick={handleGenerate}
                    >
                        בנה תפריט ✨
                    </button>
                </div>
            </div>
        </div>
    );
};

export default DaySelectionModal;

import React, { useState } from 'react';
import { useUserStore } from '../../store/userStore';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import DailyWeighInModal from '../dashboard/DailyWeighInModal';

const ProgressHome: React.FC = () => {
    const { profile, weightHistory, logWeight } = useUserStore();
    const [showWeighInModal, setShowWeighInModal] = useState(false);

    // Prepare data for chart
    const chartData = weightHistory
        .slice()
        .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
        .map(log => {
            const dateObj = new Date(log.date);
            return {
                ...log,
                displayDate: `${dateObj.getDate()}/${dateObj.getMonth() + 1}`,
                rawWeight: log.weight
            };
        });

    // Check if user weighed in today
    const todaysDateString = new Date().toISOString().split('T')[0];
    const todaysWeighIn = weightHistory.find(w => w.date === todaysDateString);

    const getMoodWarning = () => {
        if (!todaysWeighIn) return null;
        if (todaysWeighIn.mood === 'bad' || todaysWeighIn.mood === 'terrible') {
            return (
                <div className="bg-orange-500/10 border border-orange-500/30 rounded-xl p-4 mb-8 text-orange-200 fade-in">
                    <h4 className="font-bold flex items-center gap-2 mb-1">
                        <span className="text-xl">⚠️</span> ה-AI מזהה קושי
                    </h4>
                    <p className="text-sm opacity-90">
                        שמנו לב שציינת תחושת עייפות או רעב היום. יכול להיות שהתפריט הנוכחי במחזור דל מדי.
                        אם התחושה ממשיכה מחר, ה-AI יסדר מחדש את יחס הפחמימות כדי לעזור לך להרגיש טוב יותר.
                    </p>
                </div>
            );
        }
        return null;
    };

    return (
        <div className="fade-in max-w-4xl mx-auto pb-20">
            <header className="mb-8 text-center pt-8">
                <h1 className="title-gradient text-4xl mb-3">מעקב והתקדמות 📈</h1>
                <p className="text-muted text-lg">
                    גרף המשקל שלך והמגמות שה-AI מנתח.
                </p>
            </header>

            {getMoodWarning()}

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
                {/* Current Status Card */}
                <div className="card-glass relative overflow-hidden flex flex-col items-center justify-center text-center p-6 md:col-span-1">
                    <div className="absolute top-0 right-0 w-32 h-32 bg-purple-500 opacity-10 blur-3xl rounded-full"></div>
                    <span className="text-muted text-sm mb-2">משקל נוכחי</span>
                    <div className="text-5xl font-black text-white mb-2 relative z-10 flex items-baseline gap-1">
                        {profile?.weight} <span className="text-xl text-purple-400">ק"ג</span>
                    </div>
                    {profile?.goalWeight && (
                        <div className="text-sm text-purple-300 bg-purple-500/10 px-3 py-1 rounded-full border border-purple-500/20 mt-2">
                            יעד: {profile.goalWeight} ק"ג
                        </div>
                    )}
                </div>

                {/* Weigh-in Action Card */}
                <div
                    onClick={() => !todaysWeighIn && setShowWeighInModal(true)}
                    className={`card-glass flex flex-col items-center justify-center text-center p-6 md:col-span-2 transition-all duration-300 ${!todaysWeighIn ? 'cursor-pointer hover:border-purple-500/50 hover:bg-surface-hover/50 group' : 'border-purple-500/20 bg-purple-500/5'}`}
                >
                    <div className={`w-16 h-16 rounded-full flex items-center justify-center text-3xl mb-4 transition-transform ${todaysWeighIn ? 'bg-gradient-to-br from-purple-400 to-purple-600 text-white shadow-lg shadow-purple-500/20' : 'bg-surface-hover text-purple-400 group-hover:scale-110 group-hover:bg-purple-500/20'}`}>
                        {todaysWeighIn ? '✔️' : '⚖️'}
                    </div>

                    {!todaysWeighIn ? (
                        <>
                            <h3 className="text-xl font-bold text-white mb-2">שקילה יומית</h3>
                            <p className="text-muted max-w-sm">לחץ כאן כדי להזין את המשקל של היום ולשמור על רצף חיובי.</p>
                            <span className="mt-4 text-purple-400 font-medium opacity-0 group-hover:opacity-100 transition-opacity">הוסף נתונים &larr;</span>
                        </>
                    ) : (
                        <>
                            <h3 className="text-xl font-bold text-white mb-1">מעולה! עדכנת היום.</h3>
                            <p className="text-purple-300 text-sm">המשקל שלך נשמר. השקילה הבאה — מחר בבוקר.</p>
                            {todaysWeighIn.notes && (
                                <div className="mt-4 bg-black/20 p-3 rounded-lg text-xs italic text-muted max-w-xs border border-white/5">
                                    "{todaysWeighIn.notes}"
                                </div>
                            )}
                        </>
                    )}
                </div>
            </div>

            {/* Chart Section */}
            <div className="card-glass p-1 sm:p-6 mb-8">
                <div className="p-4 sm:p-0 mb-6 flex justify-between items-center border-b border-surface-hover/50 sm:border-0 pb-4 sm:pb-0">
                    <h3 className="text-xl font-bold text-white">מגמת ירידה (כל הזמן)</h3>
                    {weightHistory.length > 2 && (
                        <span className="bg-emerald-500/10 text-emerald-400 text-xs px-2 py-1 rounded-full border border-emerald-500/20">
                            מגמה ירוקה חיובית 👇
                        </span>
                    )}
                </div>

                {weightHistory.length < 2 ? (
                    <div className="h-64 flex flex-col items-center justify-center text-center opacity-50 bg-black/10 rounded-xl border border-dashed border-surface-hover m-4 sm:m-0">
                        <span className="text-4xl mb-3 grayscale">📉</span>
                        <p className="text-muted max-w-xs">עדיין אין מספיק נתונים לגרף. המשך להישקל כל בוקר!</p>
                    </div>
                ) : (
                    <div className="h-72 w-full mt-4 pr-4">
                        <ResponsiveContainer width="100%" height="100%">
                            <LineChart data={chartData} margin={{ top: 5, right: 20, bottom: 5, left: 0 }}>
                                <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.05)" vertical={false} />
                                <XAxis
                                    dataKey="displayDate"
                                    stroke="rgba(255,255,255,0.3)"
                                    tick={{ fill: 'rgba(255,255,255,0.5)', fontSize: 12 }}
                                    tickMargin={10}
                                    axisLine={false}
                                />
                                <YAxis
                                    domain={['dataMin - 1', 'dataMax + 1']}
                                    stroke="rgba(255,255,255,0.3)"
                                    tick={{ fill: 'rgba(255,255,255,0.5)', fontSize: 12 }}
                                    axisLine={false}
                                    tickLine={false}
                                    dx={-10}
                                />
                                <Tooltip
                                    contentStyle={{ backgroundColor: 'rgba(15, 23, 42, 0.9)', borderColor: 'rgba(168, 85, 247, 0.3)', borderRadius: '12px', color: 'white' }}
                                    itemStyle={{ color: '#c084fc', fontWeight: 'bold' }}
                                    labelStyle={{ color: 'rgba(255,255,255,0.6)', marginBottom: '5px' }}
                                    formatter={(value: any) => [`${value} ק"ג`, 'משקל']}
                                    labelFormatter={(label: any) => `תאריך: ${label}`}
                                />
                                <Line
                                    type="monotone"
                                    dataKey="rawWeight"
                                    stroke="#a855f7"
                                    strokeWidth={4}
                                    dot={{ fill: '#c084fc', r: 5, strokeWidth: 2, stroke: '#1e293b' }}
                                    activeDot={{ r: 8, fill: '#fff', stroke: '#a855f7', strokeWidth: 2 }}
                                />
                            </LineChart>
                        </ResponsiveContainer>
                    </div>
                )}
            </div>

            {/* History List */}
            {weightHistory.length > 0 && (
                <div>
                    <h3 className="text-lg font-bold text-white mb-4">היסטוריית שקילות</h3>
                    <div className="space-y-3">
                        {weightHistory.slice().reverse().map((log) => {
                            const dateObj = new Date(log.date);
                            const formattedDate = `${dateObj.getDate().toString().padStart(2, '0')}/${(dateObj.getMonth() + 1).toString().padStart(2, '0')}/${dateObj.getFullYear()}`;

                            // Mood Emoji Map
                            const moodMap: Record<string, string> = {
                                'great': '🔥', 'good': '😄', 'neutral': '😐', 'bad': '🥱', 'terrible': '😫'
                            };

                            return (
                                <div key={log.date} className="bg-surface/30 border border-surface-hover rounded-xl p-4 flex justify-between items-center transition-colors hover:bg-surface/50">
                                    <div>
                                        <div className="font-semibold text-white mb-1">{log.weight} ק"ג</div>
                                        <div className="text-xs text-muted font-mono">{formattedDate}</div>
                                    </div>
                                    <div className="flex items-center gap-3">
                                        {log.notes && (
                                            <span className="text-xs bg-black/20 px-2 py-1 rounded text-muted hidden sm:inline-block border border-white/5">
                                                יש הערה ל-AI
                                            </span>
                                        )}
                                        {log.mood && (
                                            <div className="bg-surface p-2 rounded-lg text-lg border border-surface-hover" title="הרגשה באותו יום">
                                                {moodMap[log.mood] || '😐'}
                                            </div>
                                        )}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            )}

            {showWeighInModal && (
                <DailyWeighInModal
                    currentWeight={profile?.weight || 80}
                    onClose={() => setShowWeighInModal(false)}
                    onSubmit={(weight, mood, notes) => logWeight(weight, todaysDateString, mood, notes)}
                />
            )}
        </div>
    );
};

export default ProgressHome;

import { create } from 'zustand';
import type { UserProfile, WeeklyPlan, DailyWorkout, WeightLog } from '../types';
import { calculateCaloricGoal, calculateMacros } from '../services/mathEngine';

interface UserState {
    profile: Partial<UserProfile> | null;
    onboardingStep: number;
    weeklyPlan: WeeklyPlan | null;
    dailyWorkouts: Record<string, DailyWorkout>;
    weightHistory: WeightLog[];
    updateProfile: (data: Partial<UserProfile>) => void;
    nextStep: () => void;
    prevStep: () => void;
    generateWeeklyPlan: (selectedDays: string[]) => void;
    swapMeal: (day: string, mealType: string) => void;
    swapIngredient: (day: string, mealType: string, oldIngredient: string, newIngredient: string) => Promise<{ success: boolean; requiresOverride: boolean; warningMessage?: string }>;
    forceSwapIngredient: (day: string, mealType: string, oldIngredient: string, newIngredient: string) => void;
    duplicateMeal: (day: string, mealType: string) => void;
    generateSOSSnack: (day: string) => void;
    applyCheatMealTolerance: (day: string, mealType: string, estimatedCalories: number) => void;
    logWorkout: (day: string, burnedCalories: number, durationMinutes?: number) => void;
    logWeight: (weight: number, date: string, mood?: WeightLog['mood'], notes?: string) => void;
    finalizeProfile: () => void;
}

export const useUserStore = create<UserState>((set, get) => ({
    profile: {
        name: '',
        gender: 'male',
        age: 30,
        height: 175,
        weight: 80,
        goalWeight: 70,
        activityLevel: 'lightly_active',
        dietaryPreferences: [],
        allergies: [],
        dislikedFoods: []
    },
    onboardingStep: 1,
    weeklyPlan: null,
    dailyWorkouts: {},
    weightHistory: [],

    updateProfile: (data) =>
        set((state) => ({
            profile: { ...state.profile, ...data }
        })),

    nextStep: () => set((state) => ({ onboardingStep: state.onboardingStep + 1 })),

    prevStep: () => set((state) => ({ onboardingStep: Math.max(1, state.onboardingStep - 1) })),

    generateWeeklyPlan: (selectedDays: string[]) => {
        // Mocking the AI creation of meals for specific days
        const mockMeal: import('../types').Meal = {
            id: 'mock-1',
            name: 'ארוחת קסם AI',
            description: 'ארוחה שנוצרה במיוחד עבורך לפי הפרופיל.',
            ingredients: ['חלבון כלשהו', 'ירק כלשהו', 'פחמימה'],
            calories: 450,
            macros: { protein: 30, carbs: 40, fat: 15 },
            prepTimeMinutes: 15,
            satietyScore: 8
        };

        const newPlan: import('../types').WeeklyPlan = {};

        selectedDays.forEach(day => {
            newPlan[day] = {
                breakfast: { ...mockMeal, id: `${day}-breakfast`, name: 'בוקר מאוזן', satietyScore: Math.floor(Math.random() * 3) + 7 }, // 7-9
                lunch: { ...mockMeal, id: `${day}-lunch`, name: 'צהריים משביע', calories: 600, satietyScore: Math.floor(Math.random() * 3) + 8 }, // 8-10
                dinner: { ...mockMeal, id: `${day}-dinner`, name: 'ערב קליל', calories: 350, satietyScore: Math.floor(Math.random() * 4) + 5 }, // 5-8
                snack: { ...mockMeal, id: `${day}-snack`, name: 'נשנוש ביניים', calories: 150, satietyScore: Math.floor(Math.random() * 3) + 4 } // 4-6
            };
        });

        set({ weeklyPlan: newPlan });
    },

    swapMeal: (day: string, mealType: string) => {
        set((state) => {
            if (!state.weeklyPlan || !state.weeklyPlan[day]) return state;

            const existingMeal = state.weeklyPlan[day][mealType];

            return {
                weeklyPlan: {
                    ...state.weeklyPlan,
                    [day]: {
                        ...state.weeklyPlan[day],
                        [mealType]: {
                            ...existingMeal,
                            name: `${existingMeal.name} (גרסה חלופית)`,
                            description: 'ה-AI החליף לך את המנה הזו במשהו אחר שמתאים לערכים שלך!',
                            calories: existingMeal.calories + Math.floor(Math.random() * 40 - 20),
                            satietyScore: Math.min(10, Math.max(1, (existingMeal.satietyScore || 7) + (Math.random() > 0.5 ? 1 : -1)))
                        }
                    }
                }
            };
        });
    },

    swapIngredient: async (day: string, mealType: string, oldIngredient: string, newIngredient: string) => {
        return new Promise((resolve) => {
            // Mock AI Request Delay
            setTimeout(() => {
                const state = get();
                if (!state.weeklyPlan || !state.weeklyPlan[day]) {
                    resolve({ success: false, requiresOverride: false, warningMessage: 'Meal not found' });
                    return;
                }

                const existingMeal = state.weeklyPlan[day][mealType];
                const isHighCalorieSwap = newIngredient.includes('אורז') || newIngredient.includes('פסטה') || newIngredient.includes('לחם');

                // If it's a "bad" swap, we warn the user and don't change state yet.
                // The UI will have to call a "forceSwapIngredient" or handle the override.
                if (isHighCalorieSwap) {
                    resolve({
                        success: false,
                        requiresOverride: true,
                        warningMessage: `שים לב! החלפה ל${newIngredient} תוסיף בערך 250 קלוריות למנה הזו, וזה עלול לחרוג מעט מהיעד היומי במידה ולא תקזז במקום אחר. האם להמשיך בכל זאת?`
                    });
                    return;
                }

                // If it's safe (or if we had a force override flag), we apply it:
                const updatedIngredients = existingMeal.ingredients.map(ing => ing === oldIngredient ? newIngredient : ing);

                set({
                    weeklyPlan: {
                        ...state.weeklyPlan,
                        [day]: {
                            ...state.weeklyPlan[day],
                            [mealType]: {
                                ...existingMeal,
                                ingredients: updatedIngredients,
                                name: `${existingMeal.name} (שודרג עם ${newIngredient})`
                            }
                        }
                    }
                });

                resolve({ success: true, requiresOverride: false });

            }, 1500); // 1.5s thought process
        });
    },

    forceSwapIngredient: (day: string, mealType: string, oldIngredient: string, newIngredient: string) => {
        set((state) => {
            if (!state.weeklyPlan || !state.weeklyPlan[day]) return state;

            const existingMeal = state.weeklyPlan[day][mealType];
            const updatedIngredients = existingMeal.ingredients.map(ing => ing === oldIngredient ? newIngredient : ing);

            // Assume the worst - it adds 250 calories. In a real app the AI would give us the exact diff to apply.
            const fakeCalorieBump = (newIngredient.includes('אורז') || newIngredient.includes('פסטה') || newIngredient.includes('לחם')) ? 250 : 50;

            return {
                weeklyPlan: {
                    ...state.weeklyPlan,
                    [day]: {
                        ...state.weeklyPlan[day],
                        [mealType]: {
                            ...existingMeal,
                            ingredients: updatedIngredients,
                            name: `${existingMeal.name} (שודרג עם ${newIngredient})`,
                            calories: existingMeal.calories + fakeCalorieBump
                        }
                    }
                }
            };
        });
    },

    duplicateMeal: (day: string, mealType: string) => {
        const days = ['sunday', 'monday', 'tuesday', 'wednesday', 'thursday'];
        const currentIndex = days.indexOf(day);
        if (currentIndex === -1 || currentIndex === days.length - 1) return; // Cannot duplicate thursday

        const nextDay = days[currentIndex + 1];

        set((state) => {
            if (!state.weeklyPlan || !state.weeklyPlan[day] || !state.weeklyPlan[nextDay]) return state;

            const existingMeal = state.weeklyPlan[day][mealType];

            return {
                weeklyPlan: {
                    ...state.weeklyPlan,
                    [nextDay]: {
                        ...state.weeklyPlan[nextDay],
                        lunch: { // Target is usually tomorrow's lunch for leftovers
                            ...existingMeal,
                            id: `${nextDay}-lunch-duplicated`,
                            name: `${existingMeal.name} (שאריות מאתמול)`
                        }
                    }
                }
            };
        });
    },

    generateSOSSnack: (day: string) => {
        set((state) => {
            if (!state.profile || !state.profile.targetDailyCalories || !state.weeklyPlan || !state.weeklyPlan[day]) return state;

            const todayPlan = state.weeklyPlan[day];
            const consumed =
                (todayPlan.breakfast?.calories || 0) +
                (todayPlan.lunch?.calories || 0) +
                (todayPlan.dinner?.calories || 0) +
                (todayPlan.snack?.calories || 0);

            const leftover = Math.max(0, state.profile.targetDailyCalories - consumed);
            const snackCalories = Math.min(leftover, 250); // Cap at 250 cals

            // If leftover is too small, maybe still give a tiny 50 cal snack
            const finalCalories = Math.max(snackCalories, 50);

            return {
                weeklyPlan: {
                    ...state.weeklyPlan,
                    [day]: {
                        ...todayPlan,
                        sosSnack: {
                            id: `${day}-sos`,
                            name: 'נשנוש SOS (הצלה)',
                            description: `הותאם במיוחד עבורך עם כ-${finalCalories} קלוריות כדי לאזן את הרעב מבלי להרוס את התפריט שיצרת. מבוסס על יתרת הקלוריות היומית שלך.`,
                            ingredients: ['פרי קטן', 'שקדים / אגוזים', 'יוגורט / מעדן'],
                            calories: finalCalories,
                            macros: { protein: Math.floor(finalCalories * 0.3 / 4), carbs: Math.floor(finalCalories * 0.4 / 4), fat: Math.floor(finalCalories * 0.3 / 9) },
                            prepTimeMinutes: 2,
                            satietyScore: 7
                        }
                    }
                }
            };
        });
    },

    applyCheatMealTolerance: (day: string, mealType: string, estimatedCalories: number) => {
        set((state) => {
            if (!state.weeklyPlan || !state.weeklyPlan[day]) return state;

            const dayPlan = state.weeklyPlan[day];
            const originalMeal = dayPlan[mealType];

            if (!originalMeal) return state;

            const diff = estimatedCalories - originalMeal.calories; // E.g., 1000 - 600 = +400

            const updatedMeals: Record<string, any> = {
                ...dayPlan,
                [mealType]: {
                    ...originalMeal,
                    name: '🍔 אכילה בחוץ (Cheat Meal)',
                    description: `הערכה: ${estimatedCalories} קק"ל. שאר היום עבר אופטימיזציה לאיזון החריגה.`,
                    calories: estimatedCalories,
                    ingredients: ['אוכל ממסעדה', 'הנאה'],
                    satietyScore: 9
                }
            };

            // If there's excess calories, try to trim up to 40% from other remaining meals
            if (diff > 0) {
                let remainingDiff = diff;
                const otherMeals = ['dinner', 'snack', 'lunch', 'breakfast'].filter(m => m !== mealType && updatedMeals[m]);

                for (const m of otherMeals) {
                    const meal = updatedMeals[m];
                    const maxCut = Math.floor(meal.calories * 0.4); // Can steal up to 40%
                    if (maxCut > 0) {
                        const cutAmount = Math.min(remainingDiff, maxCut);
                        updatedMeals[m] = {
                            ...meal,
                            calories: meal.calories - cutAmount,
                            description: meal.description.includes('[קוצץ')
                                ? meal.description
                                : `${meal.description} [קוצץ ב-${cutAmount} קק"ל לאיזון המסעדה]`
                        };
                        remainingDiff -= cutAmount;
                    }
                    if (remainingDiff <= 0) break;
                }
            }

            return {
                weeklyPlan: {
                    ...state.weeklyPlan,
                    [day]: updatedMeals as any
                }
            };
        });
    },

    logWorkout: (day: string, burnedCalories: number, durationMinutes?: number) => {
        set((state) => ({
            dailyWorkouts: {
                ...state.dailyWorkouts,
                [day]: { date: day, burnedCalories, durationMinutes, type: 'Seven App' }
            }
        }));
    },

    logWeight: (weight: number, date: string, mood?: WeightLog['mood'], notes?: string) => {
        set((state) => {
            const updatedHistory = [...state.weightHistory.filter(w => w.date !== date), { date, weight, mood, notes }];
            // Update current profile weight as well
            return {
                weightHistory: updatedHistory,
                profile: state.profile ? { ...state.profile, weight } : state.profile
            };
        });
    },

    finalizeProfile: () => {
        const profile = get().profile;
        if (profile) {
            // Calculate math targets based on the final input
            const targetDailyCalories = calculateCaloricGoal(profile);
            const targetMacros = calculateMacros(targetDailyCalories);

            set({
                profile: {
                    ...profile,
                    targetDailyCalories,
                    targetMacros
                }
            });
            // Here we would also save to Supabase.
        }
    }
}));
